    let to_eliminate: Vec<PlayerId> = state.players.iter()
        .filter(|p| !p.is_eliminated && !p.is_phased_out() && p.life <= 0)
        .filter(|p| !player_has_cant_lose(state, p.id))
        .map(|p| p.id)
        .collect();

    for loser in to_eliminate {
        events.push(GameEvent::PlayerLost { player_id: loser });
        super::elimination::eliminate_player(state, loser, events);  // <- runs check_game_over each iteration
        *any_performed = true;
    }
}
```

`eliminate_player` runs `check_game_over` after every single elimination (`crates/engine/src/game/elimination.rs`), and `check_game_over` latches the result and early-returns once set:

```rust
fn check_game_over(state: &mut GameState, events: &mut Vec<GameEvent>) {
    if state.match_phase != MatchPhase::InGame
        || matches!(state.waiting_for, WaitingFor::GameOver { .. })   // <- early-return once latched
    { return; }
    let living: Vec<PlayerId> = state.players.iter().filter(|p| !p.is_eliminated).map(|p| p.id).collect();
    ...
    if living.len() <= 1 {
        let winner = living.first().copied();   // <- the *other* still-dying player
        state.waiting_for = WaitingFor::GameOver { winner };
    }
}
```

